import {
  text as textTokens,
  type TypographyToken,
} from "@angi/one-design-system-tokens";

/**
 * Recursively builds dot-separated paths from a nested object type,
 * stopping at typography tokens (leaf nodes).
 *
 * Example: { heading: { xl: TypographyToken } } → "heading.xl"
 * Example: { body: { lg: { normal: TypographyToken } } } → "body.lg.normal"
 */
type TextPaths<T, Prefix extends string = ""> = {
  [K in keyof T]: T[K] extends TypographyToken
    ? `${Prefix}${K & string}`
    : T[K] extends object
      ? TextPaths<T[K], `${Prefix}${K & string}.`>
      : never;
}[keyof T];

/**
 * All available text variants, derived from the theme contract.
 * This type automatically updates when tokens are added or removed.
 */
export type TextVariant = TextPaths<typeof textTokens>;

export const DEFAULT_TEXT_VARIANT: TextVariant = "body.base.normal";
